RED.userSettings = (function() {

    var trayWidth = 700;
    var settingsVisible = false;

    var panes = [];

    function addPane(options) {
        panes.push(options);
    }

    function show(initialTab) {
        if (settingsVisible) {
            return;
        }
        if (!RED.user.hasPermission("settings.write")) {
            RED.notify(RED._("user.errors.settings"),"error");
            return;
        }
        settingsVisible = true;

        var trayOptions = {
            title: RED._("menu.label.userSettings"),
            buttons: [
                {
                    id: "node-dialog-ok",
                    text: RED._("common.label.close"),
                    class: "primary",
                    click: function() {
                        RED.tray.close();
                    }
                }
            ],
            resize: function(dimensions) {
                trayWidth = dimensions.width;
            },
            open: function(tray) {
                var trayBody = tray.find('.red-ui-tray-body');
                var settingsContent = $('<div></div>').appendTo(trayBody);
                var tabContainer = $('<div></div>',{class:"red-ui-settings-tabs-container"}).appendTo(settingsContent);

                $('<ul></ul>',{id:"user-settings-tabs"}).appendTo(tabContainer);
                var settingsTabs = RED.tabs.create({
                    id: "user-settings-tabs",
                    vertical: true,
                    onchange: function(tab) {
                        setTimeout(function() {
                            tabContents.children().hide();
                            $("#" + tab.id).show();
                            if (tab.pane.focus) {
                                tab.pane.focus();
                            }
                        },50);
                    }
                });
                var tabContents = $('<div></div>',{class:"red-ui-settings-tabs-content"}).appendTo(settingsContent);

                panes.forEach(function(pane) {
                    settingsTabs.addTab({
                        id: "red-ui-settings-tab-"+pane.id,
                        label: pane.title,
                        pane: pane
                    });
                    pane.get().hide().appendTo(tabContents);
                });
                settingsContent.i18n();
                settingsTabs.activateTab("red-ui-settings-tab-"+(initialTab||'view'))
                $(".red-ui-sidebar-shade").show();
            },
            close: function() {
                settingsVisible = false;
                panes.forEach(function(pane) {
                    if (pane.close) {
                        pane.close();
                    }
                });
                $(".red-ui-sidebar-shade").hide();

            },
            show: function() {}
        }
        if (trayWidth !== null) {
            trayOptions.width = trayWidth;
        }
        RED.tray.show(trayOptions);
    }

    function localeToName(lc) {
        var name = RED._("languages."+lc);
        return {text: (name ? name : lc), val: lc};
    }

    function compText(a, b) {
        return a.text.localeCompare(b.text);
    }

    var _darkMediaQuery = null;
    var _darkMediaListener = null;

    var _currentThemeVal = null;

    function hasCustomTheme() {
        const themes = RED.settings.theme("themes") || []
        return RED.settings.editorTheme?.theme && themes.includes(RED.settings.editorTheme.theme);
    }

    function getThemeSchemes() {
        var schemes = RED.settings.theme("schemes");
        return Array.isArray(schemes) && schemes.length > 0 ? schemes : null;
    }

    function customThemeOffersBothSchemes() {
        var schemes = getThemeSchemes();
        return !!schemes && schemes.indexOf('light') !== -1 && schemes.indexOf('dark') !== -1;
    }

    function applyDarkScheme(isDark) {
        document.documentElement.classList.toggle('nr-theme-dark', isDark);
        if (window.monaco) {
            monaco.editor.setTheme(isDark ? 'vs-dark' : 'vs');
        }
        if (RED.editor.mermaid) {
            RED.editor.mermaid.setTheme(isDark);
        }
    }

    function applyThemeClass(val) {
        var schemes = getThemeSchemes();

        // Custom theme without `schemes` declared — render as-is, don't manage dark class.
        if (hasCustomTheme() && !schemes) { return; }

        // Skip if value hasn't changed (avoids unnecessary re-renders on settings close)
        if (val === _currentThemeVal) { return; }
        _currentThemeVal = val;

        // Remove any existing OS-sync listener
        if (_darkMediaQuery && _darkMediaListener) {
            _darkMediaQuery.removeEventListener('change', _darkMediaListener);
            _darkMediaListener = null;
        }

        // Single-scheme theme: force the declared scheme, ignore the user's auto/light/dark choice.
        if (schemes && !customThemeOffersBothSchemes()) {
            applyDarkScheme(schemes.indexOf('dark') !== -1);
            return;
        }

        var isDark;
        if (val === 'dark') {
            isDark = true;
        } else if (val === 'light') {
            isDark = false;
        } else {
            // 'auto' — sync with OS preference
            _darkMediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
            isDark = _darkMediaQuery.matches;
            _darkMediaListener = function(e) {
                applyDarkScheme(e.matches);
            };
            _darkMediaQuery.addEventListener('change', _darkMediaListener);
        }

        applyDarkScheme(isDark);
    }

    var viewSettings = [
        {
            options: [
                {setting:"editor-language",local: true, label:"menu.label.view.language",options:function(done){ done([{val:'',text:RED._('menu.label.view.browserDefault')}].concat(RED.settings.theme("languages").map(localeToName).sort(compText))) }},
            ]
        },
        {
            title: "menu.label.view.appearance",
            options: [
                {setting:"view-dark-theme", local: true, label:"menu.label.view.darkThemeLabel", default: 'light', hidden: function() {
                    return hasCustomTheme() && !customThemeOffersBothSchemes();
                }, options: function(done) {
                    done([
                        {val:'auto',  text:RED._('menu.label.view.darkThemeAuto')},
                        {val:'light', text:RED._('menu.label.view.darkThemeLight')},
                        {val:'dark',  text:RED._('menu.label.view.darkThemeDark')}
                    ]);
                }, onchange: applyThemeClass},
            ]
        },
        // {
        //     options: [
        //         {setting:"theme", label:"Theme",options:function(done){ done([{val:'',text:'default'}].concat(RED.settings.theme("themes"))) }},
        //     ]
        // },
        {
            title: "menu.label.view.view",
            options: [
                {setting:"view-store-zoom",label:"menu.label.view.storeZoom", default: false, toggle:true, onchange: function(val) { if (!val) { RED.settings.removeLocal("zoom-level")}}},
                {setting:"view-store-position",label:"menu.label.view.storePosition", default: false, toggle:true, onchange: function(val) { if (!val) { RED.settings.removeLocal("scroll-positions")}}},
            ]
        },
        {
            title: "menu.label.view.grid",
            options: [
                {setting:"view-show-grid",oldSetting:"menu-menu-item-view-show-grid",label:"menu.label.view.showGrid", default: true, toggle:true,onchange:"core:toggle-show-grid"},
                {setting:"view-snap-grid",oldSetting:"menu-menu-item-view-snap-grid",label:"menu.label.view.snapGrid", default: true, toggle:true,onchange:"core:toggle-snap-grid"},
                {setting:"view-grid-size",label:"menu.label.view.gridSize",type:"number",default: 20, onchange:RED.view.gridSize}
            ]
        },
        {
            title: "menu.label.nodes",
            options: [
                {setting:"view-node-status",oldSetting:"menu-menu-item-status",label:"menu.label.displayStatus",default: true, toggle:true,onchange:"core:toggle-status"},
                {setting:"view-node-info-icon", label:"menu.label.displayInfoIcon", default: true, toggle:true,onchange:"core:toggle-node-info-icon"},
                {setting:"view-node-show-label",label:"menu.label.showNodeLabelDefault",default: true, toggle:true}
            ]
        },
        {
            title: "telemetry.label",
            options: [
                {
                    global: true,
                    setting: "telemetryEnabled",
                    label: "telemetry.settingsTitle",
                    description: "telemetry.settingsDescription",
                    toggle: true
                },
            ]
        },
        {
            title: "menu.label.other",
            options: [
                {setting:"view-show-tips",oldSettings:"menu-menu-item-show-tips",label:"menu.label.showTips",toggle:true,default:true,onchange:"core:toggle-show-tips"},
                {setting:"view-show-welcome-tours",label:"menu.label.showWelcomeTours",toggle:true,default:true}
            ]
        }
    ];

    var allSettings = {};

    function createViewPane() {

        var pane = $('<div id="red-ui-settings-tab-view" class="red-ui-help"></div>');

        var currentEditorSettings = RED.settings.get('editor') || {};
        currentEditorSettings.view = currentEditorSettings.view || {};

        viewSettings.forEach(function(section) {
            const activeOptions = section.options.filter(opt => !(opt.hidden && opt.hidden()));
            if (activeOptions.length === 0) {
                return;
            }
            if (section.title) {
                $('<h3></h3>').text(RED._(section.title)).appendTo(pane);
            }
            activeOptions.forEach(function(opt) {
                var initialState;
                if (opt.local) {
                    var rawLocal = localStorage.getItem(opt.setting);
                    if (opt.toggle) {
                        if (rawLocal === null) {
                            initialState = opt.hasOwnProperty('default') ? opt.default : false;
                        } else {
                            initialState = rawLocal === 'true';
                        }
                    } else {
                        if (rawLocal === null) {
                            initialState = opt.hasOwnProperty('default') ? opt.default : null;
                        } else {
                            initialState = rawLocal;
                        }
                    }
                } else if (opt.global) {
                    initialState = RED.settings.get(opt.setting);
                } else {
                    initialState = currentEditorSettings.view[opt.setting];
                }
                var row = $('<div class="red-ui-settings-row"></div>').appendTo(pane);
                var input;
                if (opt.toggle) {
                    let label = RED._(opt.label)
                    if (opt.description) {
                        label = `<p>${label}</p>${RED._(opt.description)}`;
                    }
                    input = $('<input id="user-settings-'+opt.setting+'" type="checkbox">').appendTo(row)
                    $('<label for="user-settings-'+opt.setting+'">'+label+'</label>').appendTo(row)
                    input.prop('checked',initialState);
                } else if (opt.options) {
                    $('<label for="user-settings-'+opt.setting+'">'+RED._(opt.label)+'</label>').appendTo(row);
                    var select = $('<select id="user-settings-'+opt.setting+'"></select>').appendTo(row);
                    if (typeof opt.options === 'function') {
                        opt.options(function(options) {
                            options.forEach(function(o) {
                                var val = o;
                                var text = o;
                                if (typeof o !== 'string') {
                                    val = o.val;
                                    text = o.text;
                                }
                                $('<option>').val(val).text(text).appendTo(select);
                            })
                        })
                        select.val(initialState);
                        if (opt.onchange) {
                            select.on('change', function() { setSelected(opt.setting, $(this).val()); });
                        }
                    } else {
                        // TODO: support other option types
                    }
                } else {
                    $('<label for="user-settings-'+opt.setting+'">'+RED._(opt.label)+'</label>').appendTo(row);
                    $('<input id="user-settings-'+opt.setting+'" type="'+(opt.type||"text")+'">').appendTo(row).val(initialState);
                }
            });
        })
        return pane;
    }

    function setSelected(id, value) {
        var opt = allSettings[id];
        if (opt.local) {
            localStorage.setItem(opt.setting,value);
            var callback = opt.onchange;
            if (typeof callback === 'string') {
                callback = RED.actions.get(callback);
            }
            if (callback) {
                callback.call(opt,value);
            }
        } else if (opt.global) {
            RED.settings.set(opt.setting, value)
        } else {
            var currentEditorSettings = RED.settings.get('editor') || {};
            currentEditorSettings.view = currentEditorSettings.view || {};
            currentEditorSettings.view[opt.setting] = value;
            RED.settings.set('editor', currentEditorSettings);
            var callback = opt.onchange;
            if (typeof callback === 'string') {
                callback = RED.actions.get(callback);
            }
            if (callback) {
                callback.call(opt,value);
            }
        }
    }
    function toggle(id) {
        var opt = allSettings[id];
        var currentEditorSettings = RED.settings.get('editor') || {};
        currentEditorSettings.view = currentEditorSettings.view || {};
        setSelected(id,!currentEditorSettings.view[opt.setting]);
    }


    function init() {
        RED.actions.add("core:show-user-settings",show);
        RED.actions.add("core:show-help", function() { show('keyboard')});

        addPane({
            id:'view',
            title: RED._("menu.label.settings"),
            get: createViewPane,
            close: function() {
                viewSettings.forEach(function(section) {
                    section.options.forEach(function(opt) {
                        if (opt.hidden && opt.hidden()) { return; }
                        var input = $("#user-settings-"+opt.setting);
                        if (opt.toggle) {
                            setSelected(opt.setting,input.prop('checked'));
                        } else {
                            setSelected(opt.setting,input.val());
                        }
                    });
                })
            }
        })

        var currentEditorSettings = RED.settings.get('editor') || {};
        currentEditorSettings.view = currentEditorSettings.view || {};
        var editorSettingsChanged = false;
        viewSettings.forEach(function(section) {
            section.options.forEach(function(opt) {
                if (opt.local) {
                    allSettings[opt.setting] = opt;
                    if (opt.onchange) {
                        var localValue = localStorage.getItem(opt.setting);
                        if (localValue === null && opt.hasOwnProperty('default')) { localValue = opt.default; }
                        var localCallback = opt.onchange;
                        if (typeof localCallback === 'string') { localCallback = RED.actions.get(localCallback); }
                        if (localCallback) { localCallback.call(opt, localValue); }
                    }
                    return;
                }
                if (opt.oldSetting) {
                    var oldValue = RED.settings.get(opt.oldSetting);
                    if (oldValue !== undefined && oldValue !== null) {
                        currentEditorSettings.view[opt.setting] = oldValue;
                        editorSettingsChanged = true;
                        RED.settings.remove(opt.oldSetting);
                    }
                }
                allSettings[opt.setting] = opt;
                var value = currentEditorSettings.view[opt.setting];
                if ((value === null || value === undefined) && opt.hasOwnProperty('default')) {
                    value = opt.default;
                    currentEditorSettings.view[opt.setting] = value;
                    editorSettingsChanged = true;
                }

                if (opt.onchange) {
                    var callback = opt.onchange;
                    if (typeof callback === 'string') {
                        callback = RED.actions.get(callback);
                    }
                    if (callback) {
                        callback.call(opt,value);
                    }
                }
            });
        });
        if (editorSettingsChanged) {
            RED.settings.set('editor',currentEditorSettings);
        }

    }
    return {
        init: init,
        toggle: toggle,
        show: show,
        add: addPane
    };
})();
